// Parse Google Doc content into a content_queue entry
// Expected format in doc:
// KEYWORD: investir en Thaïlande
// BRAND: reflexion
// TYPE: faq
// PRIORITY: 8
// NOTES: Focus on foreign buyers, mention FET form

const filename = $input.first().json.name || 'untitled';
const content = $('GDrive: Get Doc Content').first().binary?.data
  ? Buffer.from($('GDrive: Get Doc Content').first().binary.data, 'base64').toString('utf-8')
  : '';

const lines = content.split('\n').map(l => l.trim()).filter(Boolean);
const meta = {};
const noteLines = [];
let inNotes = false;

for (const line of lines) {
  if (line.startsWith('KEYWORD:')) { meta.keyword = line.replace('KEYWORD:', '').trim(); }
  else if (line.startsWith('BRAND:')) { meta.brand = line.replace('BRAND:', '').trim().toLowerCase(); }
  else if (line.startsWith('TYPE:')) { meta.content_type = line.replace('TYPE:', '').trim().toLowerCase(); }
  else if (line.startsWith('PRIORITY:')) { meta.priority = parseInt(line.replace('PRIORITY:', '').trim()) || 5; }
  else if (line.startsWith('NOTES:')) { inNotes = true; noteLines.push(line.replace('NOTES:', '').trim()); }
  else if (inNotes) { noteLines.push(line); }
}

meta.notes = noteLines.join('\n').trim();
meta.source = 'gdrive';
meta.gdrive_file_id = $('GDrive: List New Files').first().json.id;
meta.gdrive_filename = filename;

if (!meta.keyword) {
  // Use filename as keyword fallback
  meta.keyword = filename.replace(/\..*$/, '').replace(/-/g, ' ');
}
if (!meta.brand) meta.brand = 'reflexion';
if (!meta.content_type) meta.content_type = 'faq';
if (!meta.priority) meta.priority = 5;

return [{ json: meta }];
